CREATE TABLE IF NOT EXISTS repos (id BIGSERIAL PRIMARY KEY, owner TEXT NOT NULL, name TEXT NOT NULL, installation_id BIGINT NOT NULL, UNIQUE(owner,name));
CREATE TABLE IF NOT EXISTS pull_requests (id BIGSERIAL PRIMARY KEY, repo_id BIGINT NOT NULL REFERENCES repos(id), number INTEGER NOT NULL, title TEXT NOT NULL, author TEXT NOT NULL, head_sha TEXT NOT NULL, files_changed JSONB NOT NULL, risk_tier TEXT NOT NULL CHECK (risk_tier IN ('auto-mergeable','quick-glance','deep-review')), risk_rationale TEXT NOT NULL, risk_confidence DOUBLE PRECISION NOT NULL, scored_at TIMESTAMPTZ NOT NULL, UNIQUE(repo_id,number));
CREATE TABLE IF NOT EXISTS outcomes (pr_id BIGINT PRIMARY KEY REFERENCES pull_requests(id), outcome_type TEXT NOT NULL, reverted_by_pr_id BIGINT REFERENCES pull_requests(id), detected_at TIMESTAMPTZ NOT NULL);
CREATE TABLE IF NOT EXISTS file_risk_stats (repo_id BIGINT NOT NULL REFERENCES repos(id), path_pattern TEXT NOT NULL, total_prs INTEGER NOT NULL DEFAULT 0, reverted_prs INTEGER NOT NULL DEFAULT 0, updated_at TIMESTAMPTZ NOT NULL, PRIMARY KEY(repo_id,path_pattern));
CREATE INDEX IF NOT EXISTS pull_requests_repo_scored_at_idx ON pull_requests(repo_id,scored_at DESC);
